import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Loader2, ImageIcon, Sparkles, Database, Trash, ArrowLeft, 
  Tag, Eye, Edit2, Check, X, Calendar, ShoppingBasket 
} from 'lucide-react';

// --- CONFIGURACIÓN ---
const API_URL = "http://localhost:5000"; 
const CLOUD_NAME = "dwpgncjgn";

const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();

  // Estados
  const filaInicial = () => ({ 
    id: Math.random(), 
    producto: '', 
    precioNuevo: '', 
    precioViejo: '', 
    stock: '', 
    categoria: 'Almacén', 
    fotoSugerida: null 
  });
  
  const [filas, setFilas] = useState([filaInicial()]);
  const [publicados, setPublicados] = useState([]);
  const [galeria, setGaleria] = useState([]);
  const [fechas, setFechas] = useState({ inicio: '', fin: '' });
  const [cargando, setCargando] = useState(false);
  const [editandoId, setEditandoId] = useState(null);
  const [tempData, setTempData] = useState({});

  // --- CARGAR DATOS ---
  const cargarDatos = useCallback(async () => {
    try {
      const [resOfertas, resGaleria] = await Promise.all([
        axios.get(`${API_URL}/api/ofertas/local/${localId}`),
        axios.get(`${API_URL}/api/galeria`)
      ]);
      setPublicados(resOfertas.data || []);
      setGaleria(resGaleria.data || []);
    } catch (e) {
      console.error("Error al sincronizar con la nube", e);
    }
  }, [localId]);

  useEffect(() => {
    cargarDatos();
  }, [cargarDatos]);

  // --- BUSCADOR DE IMÁGENES INTELIGENTE ---
  const buscarMatch = useCallback((texto) => {
    if (!texto || texto.length < 3) return null;
    
    // Normalizamos el texto del producto (ej: "Aceite Natura" -> "aceitenatura")
    const normalizar = (t) => t?.toLowerCase()
      .normalize("NFD").replace(/[\u0300-\u036f]/g, "") 
      .replace(/[^a-z0-9]/g, ''); 

    const textoLimpio = normalizar(texto);

    // Buscamos en la galería: si el nombre de la foto está contenido en el producto o viceversa
    return galeria.find(foto => {
      const refNorm = normalizar(foto.nombreReferencia || foto.publicId);
      return textoLimpio.includes(refNorm) || refNorm.includes(textoLimpio);
    });
  }, [galeria]);

  // --- MANEJO DE TABLA (CARGA MASIVA) ---
  const handlePaste = (e) => {
    e.preventDefault();
    const data = e.clipboardData.getData('Text');
    const lineas = data.split(/\r?\n/).filter(line => line.trim() !== '');
    
    const nuevas = lineas.map(line => {
      const celdas = line.split('\t');
      const nombre = celdas[0]?.trim() || '';
      const match = buscarMatch(nombre);
      return { 
        id: Math.random(), 
        producto: nombre, 
        precioNuevo: celdas[1] || '', 
        precioViejo: celdas[2] || '', 
        stock: celdas[3] || 0, 
        categoria: celdas[4] || 'Almacén', 
        fotoSugerida: match ? match.publicId : null 
      };
    });
    setFilas(nuevas);
  };

  const handleInputChange = (id, campo, valor) => {
    const nuevas = filas.map(f => {
      if (f.id === id) {
        const actualizado = { ...f, [campo]: valor };
        if (campo === 'producto') {
          const m = buscarMatch(valor);
          actualizado.fotoSugerida = m ? m.publicId : null;
        }
        return actualizado;
      }
      return f;
    });
    setFilas(nuevas);
  };

  const publicarTodo = async () => {
    if (!fechas.inicio || !fechas.fin) return alert("Por favor, selecciona fechas de validez.");
    
    const filasValidas = filas.filter(f => f.producto && f.precioNuevo);
    if (filasValidas.length === 0) return alert("No hay productos válidos para publicar.");

    setCargando(true);
    try {
      const promesas = filasValidas.map(f => {
        return axios.post(`${API_URL}/api/ofertas`, {
          producto: f.producto,
          precioNuevo: Number(f.precioNuevo),
          precioViejo: Number(f.precioViejo || f.precioNuevo),
          stock: Number(f.stock),
          categoria: f.categoria,
          publicId: f.fotoSugerida || 'placeholder_id',
          local: localId,
          publicado: true,
          fechaInicioOferta: fechas.inicio,
          fechaFinOferta: fechas.fin
        });
      });
      await Promise.all(promesas);
      alert("¡Lote publicado correctamente!");
      setFilas([filaInicial()]);
      cargarDatos();
    } catch (e) {
      alert("Error al publicar.");
    } finally {
      setCargando(false);
    }
  };

  // --- ACCIONES CRUD ---
  const eliminarOferta = async (id) => {
    if (!window.confirm("¿Eliminar esta oferta?")) return;
    try {
      await axios.delete(`${API_URL}/api/ofertas/${id}`);
      cargarDatos();
    } catch (e) {
      alert("Error al eliminar.");
    }
  };

  const guardarEdicion = async (id) => {
    try {
      await axios.put(`${API_URL}/api/ofertas/${id}`, tempData);
      setEditandoId(null);
      cargarDatos();
    } catch (e) {
      alert("Error al actualizar.");
    }
  };

  // --- RENDERIZADO DE IMAGEN (Optimizado para fotos sueltas) ---
  const renderFoto = (publicId, size = "w_100,h_100") => {
    if (!publicId || publicId === 'placeholder_id') {
      return (
        <div style={{ width: '50px', height: '50px', background: '#f1f5f9', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <ImageIcon color="#cbd5e1" size={20}/>
        </div>
      );
    }
    
    // Cloudinary URL limpia
    const url = `https://res.cloudinary.com/${CLOUD_NAME}/image/upload/${size},c_fill/f_auto,q_auto/v1/${publicId}`;

    return (
      <img 
        src={url} 
        style={{ width: '50px', height: '50px', borderRadius: '8px', objectFit: 'cover', background: '#f1f5f9' }} 
        alt="thumb" 
        onError={(e) => { e.target.src = "https://via.placeholder.com/50?text=Error"; }}
      />
    );
  };

  return (
    <div style={{ padding: '30px', maxWidth: '1300px', margin: '0 auto', background: '#f8fafc', minHeight: '100vh', fontFamily: 'system-ui' }}>
      
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <button onClick={() => navigate(-1)} style={btnBack}><ArrowLeft size={18}/> Volver</button>
        <button style={btnGaleria}><Database size={16}/> Cargar Imágenes</button>
      </div>

      <header style={{ marginBottom: '30px' }}>
        <h1 style={{ color: '#1e293b', margin: 0, display: 'flex', alignItems: 'center', gap: '12px' }}>
          <ShoppingBasket color="#e67e22" size={32}/> Gestión de Inventario
        </h1>
      </header>

      {/* CARGA MASIVA */}
      <section style={cardContainer} onPaste={handlePaste}>
        <div style={cardHeader}>
          <div style={{ color: '#e67e22', fontWeight: 'bold' }}><Sparkles size={20}/> Pegar desde Excel</div>
          <button onClick={() => setFilas([...filas, filaInicial()])} style={btnAddRow}><Plus size={16}/> Nueva Fila</button>
        </div>

        <div style={{ overflowX: 'auto' }}>
          <table style={tableStyle}>
            <thead>
              <tr style={tableHead}>
                <th style={thStyle}>Vista</th>
                <th style={thStyle}>Producto</th>
                <th style={thStyle}>P. Oferta</th>
                <th style={thStyle}>P. Viejo</th>
                <th style={thStyle}>Stock</th>
                <th style={{ width: '50px' }}></th>
              </tr>
            </thead>
            <tbody>
              {filas.map((f) => (
                <tr key={f.id} style={trStyle}>
                  <td style={tdStyle}>{renderFoto(f.fotoSugerida)}</td>
                  <td style={tdStyle}>
                    <input style={inputTable} value={f.producto} placeholder="Nombre del producto..." onChange={e => handleInputChange(f.id, 'producto', e.target.value)}/>
                  </td>
                  <td style={tdStyle}><input style={inputNum} type="number" value={f.precioNuevo} onChange={e => handleInputChange(f.id, 'precioNuevo', e.target.value)}/></td>
                  <td style={tdStyle}><input style={inputNum} type="number" value={f.precioViejo} onChange={e => handleInputChange(f.id, 'precioViejo', e.target.value)}/></td>
                  <td style={tdStyle}><input style={inputNum} type="number" value={f.stock} onChange={e => handleInputChange(f.id, 'stock', e.target.value)}/></td>
                  <td style={tdStyle}>
                    <button onClick={() => setFilas(filas.filter(x => x.id !== f.id))} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#94a3b8' }}><X size={18}/></button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div style={cardFooter}>
          <div style={{ display: 'flex', gap: '10px' }}>
            <input type="date" value={fechas.inicio} onChange={e => setFechas({...fechas, inicio: e.target.value})} style={inputDate}/>
            <input type="date" value={fechas.fin} onChange={e => setFechas({...fechas, fin: e.target.value})} style={inputDate}/>
          </div>
          <button onClick={publicarTodo} style={btnPublish} disabled={cargando}>
            {cargando ? <Loader2 className="animate-spin"/> : <Sparkles size={18}/>} PUBLICAR
          </button>
        </div>
      </section>

      {/* LISTADO DE PUBLICADOS */}
      <h2 style={{ color: '#1e293b', marginBottom: '20px' }}>Productos en la Nube ({publicados.length})</h2>
      <div style={gridStyle}>
        {publicados.map(p => (
          <div key={p._id} style={{ ...itemCard, border: editandoId === p._id ? '2px solid #e67e22' : '1px solid #e2e8f0' }}>
            <div style={itemActions}>
              {editandoId === p._id ? (
                <>
                  <button onClick={() => guardarEdicion(p._id)} style={btnCircleGreen}><Check size={14}/></button>
                  <button onClick={() => setEditandoId(null)} style={btnCircleGray}><X size={14}/></button>
                </>
              ) : (
                <>
                  <button onClick={() => { setEditandoId(p._id); setTempData(p); }} style={btnCircleBlue}><Edit2 size={14}/></button>
                  <button onClick={() => eliminarOferta(p._id)} style={btnCircleRed}><Trash size={14}/></button>
                </>
              )}
            </div>
            
            <div style={itemPreview}>{renderFoto(p.publicId, "w_200,h_150")}</div>

            {editandoId === p._id ? (
              <div style={editForm}>
                <input style={inputEdit} value={tempData.producto} onChange={e => setTempData({...tempData, producto: e.target.value})}/>
                <input style={inputEdit} type="number" value={tempData.precioNuevo} onChange={e => setTempData({...tempData, precioNuevo: e.target.value})}/>
              </div>
            ) : (
              <div style={{ textAlign: 'center' }}>
                <h4 style={itemTitle}>{p.producto}</h4>
                <div style={itemPrice}>${p.precioNuevo}</div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

// --- ESTILOS ---
const btnBack = { background: 'none', border: 'none', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: 'bold' };
const btnGaleria = { background: '#1e293b', color: 'white', border: 'none', padding: '10px 20px', borderRadius: '12px', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '8px', cursor: 'pointer' };
const cardContainer = { background: 'white', borderRadius: '20px', border: '1px solid #e2e8f0', overflow: 'hidden', marginBottom: '40px' };
const cardHeader = { padding: '20px', borderBottom: '1px solid #f1f5f9', display: 'flex', justifyContent: 'space-between' };
const btnAddRow = { background: '#f1f5f9', border: 'none', padding: '8px 15px', borderRadius: '8px', cursor: 'pointer' };
const tableStyle = { width: '100%', borderCollapse: 'collapse' };
const tableHead = { background: '#f8fafc' };
const thStyle = { padding: '15px', textAlign: 'left', color: '#64748b', fontSize: '0.75rem' };
const trStyle = { borderBottom: '1px solid #f1f5f9' };
const tdStyle = { padding: '12px 15px' };
const inputTable = { width: '100%', border: 'none', outline: 'none' };
const inputNum = { width: '70px', padding: '5px', border: '1px solid #eee', borderRadius: '4px' };
const cardFooter = { padding: '20px', display: 'flex', justifyContent: 'space-between', background: '#f8fafc' };
const inputDate = { padding: '8px', borderRadius: '8px', border: '1px solid #e2e8f0' };
const btnPublish = { background: '#e67e22', color: 'white', padding: '10px 25px', borderRadius: '10px', border: 'none', cursor: 'pointer', fontWeight: 'bold' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(220px, 1fr))', gap: '20px' };
const itemCard = { background: 'white', padding: '15px', borderRadius: '20px', position: 'relative' };
const itemActions = { position: 'absolute', top: '10px', right: '10px', display: 'flex', gap: '5px' };
const itemPreview = { height: '120px', display: 'flex', justifyContent: 'center', alignItems: 'center', marginBottom: '10px' };
const itemTitle = { margin: '5px 0', fontSize: '0.9rem', color: '#1e293b' };
const itemPrice = { fontWeight: 'bold', color: '#e67e22' };
const editForm = { display: 'flex', flexDirection: 'column', gap: '5px' };
const inputEdit = { padding: '5px', borderRadius: '4px', border: '1px solid #ddd' };
const btnCircleBlue = { background: '#eff6ff', border: 'none', borderRadius: '50%', width: '30px', height: '30px', cursor: 'pointer', color: '#3b82f6' };
const btnCircleRed = { background: '#fee2e2', border: 'none', borderRadius: '50%', width: '30px', height: '30px', cursor: 'pointer', color: '#ef4444' };
const btnCircleGreen = { background: '#dcfce7', border: 'none', borderRadius: '50%', width: '30px', height: '30px', cursor: 'pointer', color: '#16a34a' };
const btnCircleGray = { background: '#f1f5f9', border: 'none', borderRadius: '50%', width: '30px', height: '30px', cursor: 'pointer' };

export default GestionOfertas;
